import{c as r,Q as t,j as a,m as l}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"复旦大学","description":"复旦大学脑科学研究院/类脑智能科学与技术研究院博士项目指南 — 计算神经科学/AI+脑科学方向","frontmatter":{"title":"复旦大学","description":"复旦大学脑科学研究院/类脑智能科学与技术研究院博士项目指南 — 计算神经科学/AI+脑科学方向","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["neuroscience","bci","bme"],"tags":["复旦大学","上海",985,"C9"],"admission-year":2027},"headers":[],"relativePath":"universities/fudan.md","filePath":"universities/fudan.md","lastUpdated":1780110618000}'),n={name:"universities/fudan.md"};function i(o,e,s,u,h,g){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="复旦大学" tabindex="-1">复旦大学 <a class="header-anchor" href="#复旦大学" aria-label="Permalink to &quot;复旦大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>复旦大学在神经科学领域拥有<strong>脑科学研究院</strong>和<strong>类脑智能科学与技术研究院</strong>两大平台。类脑院以AI+脑科学交叉为特色，脑科学转化研究院以小胶质细胞等基础方向见长。与华山医院、中山医院等顶级医院有紧密合作。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.fudan.edu.cn" target="_blank" rel="noreferrer">https://www.fudan.edu.cn</a></li><li>研究生院: <a href="https://gs.fudan.edu.cn" target="_blank" rel="noreferrer">https://gs.fudan.edu.cn</a></li><li>类脑智能研究院: <a href="https://istbi.fudan.edu.cn" target="_blank" rel="noreferrer">https://istbi.fudan.edu.cn</a></li><li>脑科学研究院: <a href="https://iobs.fudan.edu.cn" target="_blank" rel="noreferrer">https://iobs.fudan.edu.cn</a></li><li>脑科学转化研究院: <a href="https://itbr.fudan.edu.cn" target="_blank" rel="noreferrer">https://itbr.fudan.edu.cn</a></li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-类脑智能-计算神经科学方向-——" tabindex="-1">—— 类脑智能 / 计算神经科学方向 —— <a class="header-anchor" href="#——-类脑智能-计算神经科学方向-——" aria-label="Permalink to &quot;—— 类脑智能 / 计算神经科学方向 ——&quot;">​</a></h3><h4 id="纪鹏-—-研究员、博导" tabindex="-1">纪鹏 — 研究员、博导 <a class="header-anchor" href="#纪鹏-—-研究员、博导" aria-label="Permalink to &quot;纪鹏 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 类脑智能科学与技术研究院</li><li><strong>个人主页</strong>: <a href="https://faculty.fudan.edu.cn/pengji" target="_blank" rel="noreferrer">https://faculty.fudan.edu.cn/pengji</a></li><li><strong>人才称号</strong>: 浦江人才、上海高校特聘教授（东方学者）</li><li><strong>招生状态</strong>: 🟢 <strong>2026年尚有名额</strong></li></ul><p><strong>研究方向</strong>:</p><ul><li>复杂系统与神经元网络建模</li><li>机器学习算法</li><li>人和斑马鱼脑结构/功能影像分析</li><li>计算神经科学</li></ul><p><strong>招生专业</strong>: 应用数学、生物医学工程</p><p><strong>代表性论文</strong>: <em>Nature Physics</em>, <em>Nature Communications</em>, <em>Physics Reports</em>, <em>PRL</em></p><hr><h4 id="尤佳-—-青年研究员、博导" tabindex="-1">尤佳 — 青年研究员、博导 <a class="header-anchor" href="#尤佳-—-青年研究员、博导" aria-label="Permalink to &quot;尤佳 — 青年研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 类脑智能科学与技术研究院</li><li><strong>荣誉</strong>: 2025年&quot;上海科技青年35人引领计划&quot;（U35）、国家级青年人才</li></ul><p><strong>研究方向</strong>:</p><ul><li>大数据挖掘方法与生物/临床医学交叉</li><li><strong>脑重大疾病智能诊断与预测</strong>（阿尔茨海默病等）</li><li>多组学数据分析</li></ul><p><strong>代表性论文</strong>: <em>Cell</em>（封面论文）、<em>Nature Metabolism</em>、<em>Nature Aging</em></p><hr><h4 id="gunter-schumann-冈特·舒曼-—-特聘教授、博导" tabindex="-1">Gunter Schumann (冈特·舒曼) — 特聘教授、博导 <a class="header-anchor" href="#gunter-schumann-冈特·舒曼-—-特聘教授、博导" aria-label="Permalink to &quot;Gunter Schumann (冈特·舒曼) — 特聘教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 类脑智能科学与技术研究院（群体神经科学中心PONS主任）</li><li><strong>身份</strong>: 欧洲科学院院士、曾任伦敦国王学院IoPPN教授</li></ul><p><strong>研究方向</strong>:</p><ul><li>多模态神经影像学（MRI/fMRI/DTI/EEG）</li><li>计算精神病学</li><li>AI在脑科学中的应用（深度学习、图神经网络）</li><li>环境因素对大脑与精神健康的影响</li></ul><p><strong>代表性论文</strong>: 400余篇，含60余篇Nature/Science及其子刊</p><hr><h3 id="——-脑科学与转化研究-——" tabindex="-1">—— 脑科学与转化研究 —— <a class="header-anchor" href="#——-脑科学与转化研究-——" aria-label="Permalink to &quot;—— 脑科学与转化研究 ——&quot;">​</a></h3><h4 id="彭勃-—-教授-二级-、博导" tabindex="-1">彭勃 — 教授（二级）、博导 <a class="header-anchor" href="#彭勃-—-教授-二级-、博导" aria-label="Permalink to &quot;彭勃 — 教授（二级）、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 脑科学转化研究院</li><li><strong>荣誉</strong>: 2026年度新时代青年先锋奖、武田-《自然》科学创新奖、亚洲青年科学家奖</li><li><strong>成果</strong>: 2025年中国神经科学重大进展（第一完成人）</li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>小胶质细胞替换疗法</strong> — 国际首次提出并实现</li><li>神经退行性疾病</li><li>脑科学与类脑研究</li></ul><p><strong>代表性论文</strong>: <em>Science</em>, <em>Nature Neuroscience</em>, <em>Nature Aging</em>, <em>Neuron</em>, <em>Cell Stem Cell</em></p><hr><h4 id="魏依娜-—-研究员、博导" tabindex="-1">魏依娜 — 研究员、博导 <a class="header-anchor" href="#魏依娜-—-研究员、博导" aria-label="Permalink to &quot;魏依娜 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 脑智研究院</li><li><strong>研究方向</strong>: 计算神经科学、脑机接口、类脑智能、睡眠与记忆、脑卒中康复评估</li><li><strong>背景</strong>: 浙江大学本硕，宾夕法尼亚州立大学博士，UCSD博士后，Allen研究所科学家</li><li><strong>代表成果</strong>: <em>Nature Communications</em>, <em>Patterns</em>, <em>Cell Reports</em>（封面论文），申请专利20余项</li></ul><hr><h4 id="刘裕峰-—-研究员、博导" tabindex="-1">刘裕峰 — 研究员、博导 <a class="header-anchor" href="#刘裕峰-—-研究员、博导" aria-label="Permalink to &quot;刘裕峰 — 研究员、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 脑智研究院（2025年加入）</li><li><strong>研究方向</strong>: AI赋能神经影像数据处理与重建、生物脑启发的类脑网络</li><li><strong>背景</strong>: 武汉大学本科、清华博士</li><li><strong>代表成果</strong>: <em>Nature</em>, <em>Nature Neuroscience</em>, <em>Nature Communications</em>, <em>CVPR</em></li></ul><hr><h2 id="_2026年博士招生" tabindex="-1">2026年博士招生 <a class="header-anchor" href="#_2026年博士招生" aria-label="Permalink to &quot;2026年博士招生&quot;">​</a></h2><ul><li>招生方式: 申请考核制</li><li>报名时间: 通常在2025年11月-12月</li><li>确认招生导师: 纪鹏明确表示2026年尚有名额</li></ul><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>纪鹏课题组明确有2026年名额</strong>，且招收生物医学工程背景 — 可直接联系</li><li><strong>计算神经科学/AI+脑科学最匹配</strong>：你的MATLAB/Python编程能力是竞争优势</li><li><strong>尤佳课题组</strong>：阿尔茨海默病智能诊断方向与你的脑类器官AD模型经验可衔接</li><li><strong>魏依娜课题组</strong>：脑机接口+计算神经科学，跨学科背景契合</li><li>复旦与上交互补：复旦偏基础/计算，上交偏工程/应用</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://faculty.fudan.edu.cn/pengji" target="_blank" rel="noreferrer">纪鹏主页</a>（访问日期: 2026-05-25）</li><li><a href="https://istbi.fudan.edu.cn" target="_blank" rel="noreferrer">类脑智能研究院</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以复旦大学研究生院官网最新公告为准。</em></p>',51)])])}const m=r(n,[["render",i]]);export{c as __pageData,m as default};
